// Transform Notion pages into Supabase-ready rows
const items = $input.all();
const tasks = items.map(item => {
  const props = item.json.properties;

  // Extract title
  const name = props['Task name']?.title?.[0]?.plain_text || 'Untitled';

  // Extract due date
  const dueDate = props['Due']?.date?.start || null;

  // Extract priority
  const priority = props['Priority']?.select?.name || null;

  // Extract status
  const status = props['Status']?.status?.name || 'Not Started';

  // Extract project name from relation (resolved)
  const projectName = props['Project']?.relation?.[0]?.id ? null : null;
  // Note: project name resolution requires a separate Notion API call
  // For now, we'll resolve it in the next node
  const projectRelation = props['Project']?.relation || [];

  // Extract tags
  const tags = (props['Tags']?.multi_select || []).map(t => t.name);

  return {
    json: {
      notion_page_id: item.json.id,
      name,
      due_date: dueDate,
      priority,
      status,
      project_relation_id: projectRelation.length > 0 ? projectRelation[0].id : null,
      tags,
      last_synced: new Date().toISOString()
    }
  };
});

return tasks;

