=INSERT INTO notion_tasks (notion_page_id, name, due_date, priority, status, project_name, tags, last_synced) VALUES {{ $items.map(i => {
  const j = i.json;
  const name = j.name.replace(/'/g, "''");
  const projectName = j.project_name ? "'" + j.project_name.replace(/'/g, "''") + "'" : 'NULL';
  const dueDate = j.due_date ? "'" + j.due_date + "'" : 'NULL';
  const priority = j.priority ? "'" + j.priority + "'" : 'NULL';
  const tags = j.tags && j.tags.length > 0 ? "ARRAY[" + j.tags.map(t => "'" + t.replace(/'/g, "''") + "'").join(',') + "]" : 'NULL';
  return `('${j.notion_page_id}', '${name}', ${dueDate}, ${priority}, '${j.status}', ${projectName}, ${tags}, '${j.last_synced}')`;
}).join(',\n') }} ON CONFLICT (notion_page_id) DO UPDATE SET name = EXCLUDED.name, due_date = EXCLUDED.due_date, priority = EXCLUDED.priority, status = EXCLUDED.status, project_name = EXCLUDED.project_name, tags = EXCLUDED.tags, last_synced = EXCLUDED.last_synced;
